import * as ex from "excalibur";

export const PORTRAIT_FRAME_OFFSET = {
  cols: 6,
  rows: 6,
  naturalSize: 2048,
  slice: 128,
  sliceL: 128,
  sliceT: 128,
  sliceB: 128,
  categoryCol: { brave: 0, common: 1, mystic: 2, elegant: 3, audience: 4, enemy: 5 } as Record<
    string,
    number
  >,
};

export function createPortraitFrameGroup(
  frameImage: ex.ImageSource,
  category: string,
  rank: number | string,
  baseW: number,
  baseH: number,
  frameWidth: number,
): ex.GraphicsGroup {
  const f = PORTRAIT_FRAME_OFFSET;
  const col = f.categoryCol[category] ?? f.categoryCol.common;
  const row = Math.max(0, Math.min(f.rows - 1, Number(rank) || 0));
  const tw = f.naturalSize / f.cols;
  const th = f.naturalSize / f.rows;
  const sL = f.sliceL;
  const sT = f.sliceT;
  const sB = f.sliceB;
  const wL = frameWidth;
  const wT = frameWidth;
  const wB = frameWidth;
  const wVar = baseW - 2 * wL;
  const hVar = baseH - wT - wB;
  const sWVar = tw - 2 * sL;
  const sHVar = th - sT - sB;
  const cells = [
    { w: wL, h: wT, sx: 0, sy: 0, dx: 0, dy: 0, sw: sL, sh: sT },
    { w: wVar, h: wT, sx: sL, sy: 0, dx: wL, dy: 0, sw: sWVar, sh: sT },
    { w: wL, h: wT, sx: tw - sL, sy: 0, dx: baseW - wL, dy: 0, sw: sL, sh: sT },
    { w: wL, h: hVar, sx: 0, sy: sT, dx: 0, dy: wT, sw: sL, sh: sHVar },
    { w: wVar, h: hVar, sx: sL, sy: sT, dx: wL, dy: wT, sw: sWVar, sh: sHVar },
    { w: wL, h: hVar, sx: tw - sL, sy: sT, dx: baseW - wL, dy: wT, sw: sL, sh: sHVar },
    { w: wL, h: wB, sx: 0, sy: th - sB, dx: 0, dy: baseH - wB, sw: sL, sh: sB },
    { w: wVar, h: wB, sx: sL, sy: th - sB, dx: wL, dy: baseH - wB, sw: sWVar, sh: sB },
    { w: wL, h: wB, sx: tw - sL, sy: th - sB, dx: baseW - wL, dy: baseH - wB, sw: sL, sh: sB },
  ];
  return new ex.GraphicsGroup({
    members: cells.map((cell) => ({
      graphic: new ex.Sprite({
        image: frameImage,
        sourceView: {
          x: col * tw + cell.sx,
          y: row * th + cell.sy,
          width: cell.sw,
          height: cell.sh,
        },
        destSize: { width: cell.w, height: cell.h },
      }),
      offset: new ex.Vector(cell.dx, cell.dy),
    })),
    width: baseW,
    height: baseH,
  });
}
